SELECT S.CONTRATO, COUNT(DISTINCT S.PK_SIAPE) AS QTD FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA CH ON CH.SIAPE = S.PK_SIAPE WHERE CH.ANO = 2021 AND CH.SEMESTRE = 1 AND CH.SIGLA_CAMPUS = 'FOR' AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%libras%') GROUP BY S.CONTRATO HAVING COUNT(DISTINCT S.PK_SIAPE) = 1 ORDER BY S.CONTRATO